defmodule XmlParser do
  use SweetXml

  def parse(xml) do
    xml
    |> xpath("/*")
    |> Enum.map(&parse_node/1)
  end

  defp parse_node({:tag, _, _, _, _}) do
    {:ok, :root}
  end

  defp parse_node({:tag, name, _, _, children}) when is_list(children) do
    {:ok, name}
  end
end

