end

defmodule XmlParser.Socket do
  use Phoenix.Socket

  def connect(_params, socket) do
    {:ok, socket}
  end

  def id(socket), do: socket.assigns.user_id

  # Channels can be used to communicate between the server and the client.
  # In this case it's a simple greeting channel that responds with "Hello"
  def handle_in("greet", _, socket) do
    {:reply, :ok, %{socket | topic: "xml"}}
  end
end

